queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?activityname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasActivities ?child ; p:hasResorts ?parent . } GROUP BY ?child }
  ?child p:activityName ?activityname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Resorts } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?activityname WHERE {
  ?resorts_activities a :Resorts_Activities .
  ?activities a :Activities .
  ?resorts_activities p:hasActivities ?activities .
  ?resorts a :Resorts .
  ?resorts_activities p:hasResorts ?resorts .
  ?resorts p:name ?name .
  ?activities p:activityName ?activityname .
} }
  collective: { SELECT ?activityname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasActivities ?child ; p:hasResorts ?parent . } GROUP BY ?child }
  ?child p:activityName ?activityname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Resorts } }
  FILTER(?nf = ?total)
} }
}
